//! Auto-generated by the spec-word-compliance workflow for area:
//! "Default style selection + general style flags
//!  (next/default/autoRedefine/hidden/semiHidden/latentStyles)".
//!
//! Each `#[test]` encodes a Word-consumption rule mined from ECMA-376 /
//! ISO/IEC 29500-1 / MS-OI29500. A FAIL here means stemma diverges from Word —
//! i.e. it encodes a REAL Word-compliance gap. Do NOT weaken an assertion to
//! make it pass; a failing assertion is the finding.
//!
//! Methodology note (consumption vs. save): stemma round-trips untouched
//! content byte-verbatim, so these tests assert on the READ side
//! (`read_accepted()` / `read_rejected()` text) and on package validity
//! (`validate()` opens-clean), NOT on re-serialized XML of unedited input.

use std::io::Read;

use stemma::api::Document;

// ─── Prelude / plumbing ─────────────────────────────────────────────────────

/// Build a valid minimal `.docx`. `body_xml` is wrapped in
/// `<w:document><w:body>…</w:body></w:document>`. `extra_parts` are additional
/// package parts (e.g. `("word/styles.xml", "<?xml …><w:styles>…")`); content-type
/// overrides + a document rel are synthesized for the parts we know about.
fn make_docx(body_xml: &str, extra_parts: &[(&str, &str)]) -> Vec<u8> {
    let document_xml = format!(
        r#"<?xml version="1.0" encoding="UTF-8" standalone="yes"?>
<w:document xmlns:w="http://schemas.openxmlformats.org/wordprocessingml/2006/main"><w:body>{body_xml}</w:body></w:document>"#
    );

    // Content-type overrides for known extra parts.
    let mut overrides = String::from(
        r#"<Override PartName="/word/document.xml" ContentType="application/vnd.openxmlformats-officedocument.wordprocessingml.document.main+xml"/>"#,
    );
    // Document-level relationships for known extra parts.
    let mut doc_rels_entries = String::new();
    let mut rel_counter = 1;
    for (part, _) in extra_parts {
        match *part {
            "word/styles.xml" => {
                overrides.push_str(
                    r#"<Override PartName="/word/styles.xml" ContentType="application/vnd.openxmlformats-officedocument.wordprocessingml.styles+xml"/>"#,
                );
                doc_rels_entries.push_str(&format!(
                    r#"<Relationship Id="rIdS{rel_counter}" Type="http://schemas.openxmlformats.org/officeDocument/2006/relationships/styles" Target="styles.xml"/>"#
                ));
                rel_counter += 1;
            }
            "word/numbering.xml" => {
                overrides.push_str(
                    r#"<Override PartName="/word/numbering.xml" ContentType="application/vnd.openxmlformats-officedocument.wordprocessingml.numbering+xml"/>"#,
                );
                doc_rels_entries.push_str(&format!(
                    r#"<Relationship Id="rIdN{rel_counter}" Type="http://schemas.openxmlformats.org/officeDocument/2006/relationships/numbering" Target="numbering.xml"/>"#
                ));
                rel_counter += 1;
            }
            other => {
                panic!("make_docx: unknown extra part {other}; add a content-type override + rel")
            }
        }
    }

    let content_types = format!(
        r#"<?xml version="1.0" encoding="UTF-8" standalone="yes"?><Types xmlns="http://schemas.openxmlformats.org/package/2006/content-types"><Default Extension="rels" ContentType="application/vnd.openxmlformats-package.relationships+xml"/><Default Extension="xml" ContentType="application/xml"/>{overrides}</Types>"#
    );
    let rels = r#"<?xml version="1.0" encoding="UTF-8" standalone="yes"?>
<Relationships xmlns="http://schemas.openxmlformats.org/package/2006/relationships"><Relationship Id="rId1" Type="http://schemas.openxmlformats.org/officeDocument/2006/relationships/officeDocument" Target="word/document.xml"/></Relationships>"#;
    let doc_rels = format!(
        r#"<?xml version="1.0" encoding="UTF-8" standalone="yes"?>
<Relationships xmlns="http://schemas.openxmlformats.org/package/2006/relationships">{doc_rels_entries}</Relationships>"#
    );

    use std::io::Write;
    use zip::write::FileOptions;
    let mut buf = Vec::new();
    {
        let mut zip = zip::ZipWriter::new(std::io::Cursor::new(&mut buf));
        let opts: FileOptions = FileOptions::default();
        zip.start_file("[Content_Types].xml", opts).unwrap();
        zip.write_all(content_types.as_bytes()).unwrap();
        zip.start_file("_rels/.rels", opts).unwrap();
        zip.write_all(rels.as_bytes()).unwrap();
        zip.start_file("word/_rels/document.xml.rels", opts)
            .unwrap();
        zip.write_all(doc_rels.as_bytes()).unwrap();
        zip.start_file("word/document.xml", opts).unwrap();
        zip.write_all(document_xml.as_bytes()).unwrap();
        for (part, xml) in extra_parts {
            zip.start_file(*part, opts).unwrap();
            zip.write_all(xml.as_bytes()).unwrap();
        }
        zip.finish().unwrap();
    }
    buf
}

/// Unzip and return `word/document.xml` as a String.
#[allow(dead_code)]
fn document_xml_of(docx: &[u8]) -> String {
    let mut archive = zip::ZipArchive::new(std::io::Cursor::new(docx)).expect("open docx zip");
    let mut file = archive
        .by_name("word/document.xml")
        .expect("word/document.xml present");
    let mut out = String::new();
    file.read_to_string(&mut out).expect("read document.xml");
    out
}

/// Parse → serialize(ExportOptions::default()) → extract document.xml.
#[allow(dead_code)]
fn reserialize(bytes: &[u8]) -> String {
    let doc = Document::parse(bytes).expect("parse for reserialize");
    let out = doc
        .serialize(&stemma::ExportOptions::default())
        .expect("serialize");
    document_xml_of(&out)
}

/// Assert `validate()` reports no errors, with a rule-bearing message.
fn assert_opens_clean(bytes: &[u8], rule: &str) {
    let report = stemma::api::validate(bytes);
    assert!(
        report.ok && report.issues.is_empty(),
        "{rule} — expected the package to open clean (validate() reports no errors), \
         but got issues: {:?}",
        report.issues
    );
}

fn accept_text(bytes: &[u8]) -> String {
    let doc = Document::parse(bytes).expect("parse for accept text");
    doc.read_accepted()
        .expect("read_accepted")
        .to_text()
        .trim()
        .to_string()
}

#[allow(dead_code)]
fn reject_text(bytes: &[u8]) -> String {
    let doc = Document::parse(bytes).expect("parse for reject text");
    doc.read_rejected()
        .expect("read_rejected")
        .to_text()
        .trim()
        .to_string()
}

// ─── Tests ──────────────────────────────────────────────────────────────────

#[test]
fn based_on_cross_type_ignored_opens_clean() {
    let styles = r#"<?xml version="1.0" encoding="UTF-8" standalone="yes"?>
<w:styles xmlns:w="http://schemas.openxmlformats.org/wordprocessingml/2006/main"><w:style w:type="character" w:styleId="CharOnly"><w:name w:val="Char Only"/><w:rPr><w:b/></w:rPr></w:style><w:style w:type="paragraph" w:styleId="BodyPara"><w:name w:val="Body Para"/><w:basedOn w:val="CharOnly"/><w:rPr><w:sz w:val="24"/></w:rPr></w:style></w:styles>"#;
    let b = make_docx(
        r#"<w:p><w:pPr><w:pStyle w:val="BodyPara"/></w:pPr><w:r><w:t>Body content here.</w:t></w:r></w:p><w:sectPr/>"#,
        &[("word/styles.xml", styles)],
    );
    assert_opens_clean(
        &b,
        "ECMA-376 §17.7.4.3 / ISO/IEC 29500-1 §17.7.4.3: a paragraph style whose basedOn names a character style has that element 'ignored' (defined non-error); package must open clean",
    );
    assert_eq!(
        accept_text(&b),
        "Body content here.",
        "ECMA-376 §17.7.4.3: ignoring a cross-type basedOn affects only inherited formatting, never text; accepted read view must yield the original run text unchanged"
    );
}

