#[test]
fn default_offvalue_paragraph_style_not_applied() {
    let styles = r#"<?xml version="1.0" encoding="UTF-8" standalone="yes"?><w:styles xmlns:w="http://schemas.openxmlformats.org/wordprocessingml/2006/main"><w:style w:type="paragraph" w:default="0" w:styleId="NotDefault"><w:name w:val="Not Default"/><w:rPr><w:sz w:val="56"/></w:rPr></w:style></w:styles>"#;
    let b = make_docx(
        r#"<w:p><w:r><w:t>Plain</w:t></w:r></w:p><w:sectPr/>"#,
        &[("word/styles.xml", styles)],
    );
    assert_opens_clean(
        &b,
        "ECMA-376 §17.7.4.17 / ISO/IEC 29500-1 §17.7.4.17: a default=\"0\" paragraph style is well-formed (ST_OnOff off-value); Word opens it without repair",
    );
    assert_eq!(
        accept_text(&b),
        "Plain",
        "ECMA-376 §17.7.4.17: default is ST_OnOff; \"0\"/false equals not-specified, so the style is NOT the default; visible text is the literal run and the document is consumed normally"
    );
}

#[test]
fn based_on_type_mismatch_ignored_paragraph_on_character() {
    let styles = r#"<?xml version="1.0" encoding="UTF-8" standalone="yes"?><w:styles xmlns:w="http://schemas.openxmlformats.org/wordprocessingml/2006/main"><w:style w:type="character" w:styleId="CharBase"><w:name w:val="Char Base"/><w:rPr><w:sz w:val="56"/></w:rPr></w:style><w:style w:type="paragraph" w:styleId="Body"><w:name w:val="Body"/><w:basedOn w:val="CharBase"/></w:style></w:styles>"#;
    let b = make_docx(
        r#"<w:p><w:pPr><w:pStyle w:val="Body"/></w:pPr><w:r><w:t>Body text</w:t></w:r></w:p><w:sectPr/>"#,
        &[("word/styles.xml", styles)],
    );
    assert_opens_clean(
        &b,
        "ECMA-376 §17.7.4.3 / ISO/IEC 29500-1 §17.7.4.3: a cross-type basedOn (paragraph style basedOn a character style) is well-formed markup that Word ignores rather than rejecting; the file opens without repair",
    );
    assert_eq!(
        accept_text(&b),
        "Body text",
        "ECMA-376 §17.7.4.3: the paragraph content is unaffected by the ignored cross-type basedOn; visible text is the literal run"
    );
}
